import React, { useState, useEffect } from 'react';
import moment from 'moment';
import DataTable from '../../components/common/DataTable';
import { createResourceService } from '../../services/api.service';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import { Link } from 'react-router-dom';
import useForm from '../../hooks/useForm';
import { FormInput, FormTextarea } from '../../components/common/FormFields';

const TableForm = ({ item, onSave, apiService }) => {
    const isEditMode = Boolean(item);
    const [photoPreview, setPhotoPreview] = useState(null);
    const [photoFile, setPhotoFile] = useState(null);

    const schema = {
        fn: { required: true, label: 'First Name' },
        sn: { required: true, label: 'Last Name' },
        email: { required: true, type: 'email', label: 'Email Address' }
    };

    const { values, errors, handleChange, handleSubmit } = useForm({
        fn: isEditMode ? item.fn ?? '' : '',
        mn: isEditMode ? item.mn ?? '' : '',
        sn: isEditMode ? item.sn ?? '' : '',
        phone: isEditMode ? item.phone ?? '' : '',
        email: isEditMode ? item.email ?? '' : '',
        address: isEditMode ? item.address ?? '' : '',
    }, schema);

    useEffect(() => {
        let isMounted = true;
        if (isEditMode && item.photoUrl) {
            if (apiService && typeof apiService.getPhoto === 'function') {
                const photoUrlWithCacheBust = `${item.photoUrl}?t=${Date.now()}`;
                apiService.getPhoto(photoUrlWithCacheBust)
                    .then(response => {
                        if (isMounted) { const localUrl = URL.createObjectURL(response.data); setPhotoPreview(localUrl); }
                    }).catch(() => { if (isMounted) setPhotoPreview('/defaults/avatar.png'); });
            } else { if (isMounted) setPhotoPreview('/defaults/avatar.png'); }
        }
        return () => { isMounted = false; };
    }, [isEditMode, item, apiService]);

    const handlePhotoChange = (e) => { const file = e.target.files[0]; if (file) { setPhotoFile(file); setPhotoPreview(URL.createObjectURL(file)); } };

    const handleSave = (formValues) => {
        const formData = new FormData();
        Object.keys(formValues).forEach(key => formData.append(key, formValues[key]));
        if (photoFile) formData.append('photo', photoFile);
        onSave(formData, item?.id);
    };

    return (
        <form className='form-case' noValidate id='Table_form' onSubmit={handleSubmit(handleSave)} >
            <div className='form-row form-profile'>
                <div className='form-profile-photo'><img src={photoPreview || '/defaults/avatar.png'} alt='Profile Preview' loading='lazy' onError={(e) => { e.target.onerror = null; e.target.src = '/defaults/avatar.png'; }} /><label htmlFor='photo-upload'>Select Photo</label></div>
                <input id='photo-upload' type='file' accept='image/*' onChange={handlePhotoChange} />
                <div className='form-profile-info'>
                    <div className='form-row'>
                        <FormInput label="First Name" name="fn" placeholder="First Name" value={values.fn} error={errors.fn} onChange={handleChange} required className="w5-fx" />
                        <FormInput label="Middle Name" name="mn" placeholder="Middle Name" value={values.mn} onChange={handleChange} className="w5-fx" />
                    </div>
                    <FormInput label="Last Name" name="sn" placeholder="Last Name" value={values.sn} error={errors.sn} onChange={handleChange} required />
                </div>
            </div>
            <div className='form-dvr'></div>
            <div className='form-row'>
                <FormInput label="Phone" name="phone" placeholder="Phone Number" value={values.phone} onChange={handleChange} className="w5" autoComplete='off' />
                <FormInput label="Email Address" name="email" type="email" placeholder="Email" value={values.email} error={errors.email} onChange={handleChange} required className="w5" autoComplete='off' />
            </div>
            <FormTextarea label="Address" name="address" placeholder="Address" rows={2} value={values.address} onChange={handleChange} autoComplete='off' />
        </form>);
};

const tableService = createResourceService('employees');

const TableFilters = () => {
    const [activeTab, setActiveTab] = useState('all');
    const genderTabs = [{ key: 'all', label: 'All', value: '' }, { key: 'male', label: 'Male', value: '1' }, { key: 'female', label: 'Female', value: '2' }, { key: 'none', label: 'No Value', value: 'null' }];
    const initialLoadTime = React.useMemo(() => Date.now(), []);
    const [photoOverrides, setPhotoOverrides] = useState({});

    const handleSaveSuccess = React.useCallback((itemId, formData) => {
        if (itemId && formData.has('photo')) {
            setPhotoOverrides(prev => ({ ...prev, [itemId]: Date.now() }));
        }
    }, []);

    const tableColumns = React.useMemo(() => [
        {
            key: 'fn', label: 'Full Name', type: 0, sortable: true, render: (item, photoUrl) => {
                let displayUrl = photoUrl || '/defaults/avatar.png';
                if (displayUrl.includes('?')) displayUrl = displayUrl.split('?')[0];

                const timestampToUse = photoOverrides[item.id] || initialLoadTime;
                displayUrl = `${displayUrl}?t=${timestampToUse}`;

                return (
                    <div className='td-user'>
                        <div className='td-user-photo'><img src={displayUrl} alt={`${item.fn} ${item.sn}`} loading='lazy' onError={(e) => { e.target.onerror = null; e.target.src = '/defaults/avatar.png'; }} /></div>
                        <div className='tr-name'><b>{`${item.fn} ${item.mn ? item.mn : ''} ${item.sn}`}</b><p>{item.email}</p> </div>
                    </div>
                );
            }
        },
        { key: 'gender', label: 'Gender', type: 1, sortable: true, render: (item) => (item.gender === '1' ? 'Male' : (item.gender === '2') ? 'Female' : '') },
        { key: 'bday', label: 'Birthday', type: 1, sortable: true, render: (item) => { return item.bday ? moment(item.bday).format('MMM. DD, YYYY') : ''; } },
        { key: 'phone', label: 'Phone', type: 1, sortable: true },
        { key: 'address', label: 'Address', type: 1, sortable: true },
    ], [initialLoadTime, photoOverrides]);

    const CustomControls = ({ limit, onLimitChange, searchTerm, onSearchChange, activeFilters, onFilterChange, onRefresh, data = [], totalPages = 0 }) => {
        const handleTabClick = (tabKey, filterValue) => { setActiveTab(tabKey); onFilterChange('gender', filterValue); };
        const [showFilters, setShowFilters] = useState(false);

        return (
            <div className='pagelet'><div className='pagelet-body'>
                <div className='table-custom-case'>
                    <div className='table-custom-controls'>
                        <div className='table-limit'>
                            <p>Show</p>
                            <select name='custom-limit' value={limit} onChange={(e) => onLimitChange(e.target.value)}>
                                <option value={10}>10</option>
                                <option value={15}>15</option>
                                <option value={25}>25</option>
                                <option value={50}>50</option>
                                <option value={100}>100</option>
                            </select>
                            <p>Entries</p>
                        </div>
                        <div className='table-action'>
                            <div className='table-data-count'>{data.length.toLocaleString()}<b> Item{(data.length > 1 || totalPages > 1) ? 's' : ''}</b></div>
                            <div className='table-search'>
                                <div className='input-case'>
                                    <div className='input-group left'>
                                        <input type='text' id='table-search' placeholder='Search...' value={searchTerm} onChange={(e) => onSearchChange(e.target.value)} />
                                        <Icon icon={icons.search} />
                                    </div>
                                </div>
                            </div>
                            <button type='button' className='button icon' title='Refresh' onClick={onRefresh}><Icon icon={icons.refresh} /></button>
                        </div>
                    </div>
                </div>
            </div></div>
        )
    };

    return (
        <DataTable
            resourceName='Table'
            apiService={tableService}
            columns={tableColumns}
            FormComponent={TableForm}
            config={{ title: <span><h2>Basic Table</h2><p>Sample Table Template</p></span>, searchables: ['fn|mn|sn', 'fn|sn', 'sn|fn|mn', 'phone', 'email'], modalWidth: 'w-mm', tableControls: false, customControls: <CustomControls />, onSaveSuccess: handleSaveSuccess }}
        />);
};

export default TableFilters;